body.script:
        (async function() {
          const ns = "http://www.w3.org/1999/xhtml";
          const body = document.querySelector("body");
          if (!body) return;
          const svgRoot = document.documentElement;
          const head = document.createElementNS(ns, "head");
          body.prepend(head);
          const htmlRoot = body.parentElement && body.parentElement.namespaceURI === ns ? body.parentElement : body;
          try { Object.defineProperty(document, "head", { configurable: true, get() { return head; } }); } catch (e) {}
          try { Object.defineProperty(document, "body", { configurable: true, get() { return body; } }); } catch (e) {}
          try { Object.defineProperty(document, "documentElement", { configurable: true, get() { return htmlRoot; } }); } catch (e) {}
          try {
            Object.defineProperty(svgRoot, "className", {
              configurable: true,
              get() { return svgRoot.getAttribute("class") || ""; },
              set(value) { svgRoot.setAttribute("class", value || ""); },
            });
          } catch (e) {}
          const originalCreateElement = document.createElement.bind(document);
          document.createElement = function createElement(tagName, options) {
            return typeof tagName === "string"
              ? document.createElementNS(ns, tagName, options)
              : originalCreateElement(tagName, options);
          };

          async function loadHtmlContent() {
            try {
              const baseUrl = window.location.href.split("?")[0].split("#")[0].replace(/[^/]+$/, "");
              const response = await fetch(new URL("index.html", baseUrl));
              if (!response.ok) throw new Error(`Failed to load index.html: ${response.status}`);
              const text = await response.text();
              if (!text) throw new Error("index.html is empty");
              const parser = new DOMParser();
              const doc = parser.parseFromString(text, "text/html");
              const sourceBody = doc.body;
              const root = document.getElementById("root");
              if (root && sourceBody) {
                while (sourceBody.firstChild) {
                  const imported = document.importNode(sourceBody.firstChild, true);
                  root.appendChild(imported);
                  sourceBody.removeChild(sourceBody.firstChild);
                }
              }
              setTimeout(() => {
                document.dispatchEvent(new Event("DOMContentLoaded", { bubbles: true }));
                window.dispatchEvent(new Event("load", { bubbles: true }));
              }, 10);
            } catch (err) {
              console.error("Failed to load app content:", err);
            }
          }

          function createHeadNode(nodeDef) {
            const node = document.createElement(nodeDef.tag);
            for (const [name, value] of Object.entries(nodeDef.attrs || {})) {
              if (value === "") node.setAttribute(name, "");
              else node.setAttribute(name, value);
            }
            if (typeof nodeDef.text === "string") {
              node.textContent = nodeDef.text;
            }
            return node;
          }

          async function appendHeadNode(nodeDef) {
            const node = createHeadNode(nodeDef);
            head.appendChild(node);
            if (nodeDef.tag === "script") {
              try {
                await new Promise((resolve) => {
                  const timeout = setTimeout(() => {
                    console.warn(`Timeout loading script: ${nodeDef.attrs?.src || "[inline script]"}`);
                    resolve();
                  }, 12000);
                  node.addEventListener("load", () => { clearTimeout(timeout); resolve(); }, { once: true });
                  node.addEventListener("error", () => { clearTimeout(timeout); console.error(`Failed to load script: ${nodeDef.attrs?.src || "[inline script]"}`); resolve(); }, { once: true });
                });
              } catch (e) {
                console.error(`Error in script loading sequence: ${nodeDef.attrs?.src || "[inline script]"}`, e);
              }
            }
          }

          const headNodes = [
            { tag: "meta", attrs: { charset: "UTF-8" } },
            { tag: "meta", attrs: { name: "viewport", content: "width=device-width, initial-scale=1.0" } },
            { tag: "meta", attrs: { name: "theme-color", content: "#0a0f14" } },
            { tag: "link", attrs: { rel: "modulepreload", href: "./baremux/index.mjs?v=7" } },
            { tag: "link", attrs: { rel: "modulepreload", href: "./libcurl/index.mjs?v=7" } },
            { tag: "link", attrs: { rel: "modulepreload", href: "./epoxy/index.mjs?v=7" } },
            { tag: "link", attrs: { rel: "preconnect", href: "https://fonts.googleapis.com" } },
            { tag: "link", attrs: { rel: "preconnect", href: "https://fonts.gstatic.com", crossorigin: "" } },
            { tag: "link", attrs: { rel: "stylesheet", href: "https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&display=swap" } },
            { tag: "link", attrs: { rel: "stylesheet", href: "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.0/css/all.min.css" } },
            { tag: "link", attrs: { rel: "stylesheet", href: "./index.css?v=7" } },
            { tag: "script", attrs: { type: "module", src: "./scram/scramjet.all.js?v=7" } },
            {
              tag: "script",
              attrs: { type: "module" },
              text: 'import * as BareMuxModule from "./baremux/index.mjs?v=7"; globalThis.BareMux = BareMuxModule;'
            },
            { tag: "script", attrs: { type: "module", src: "./register-sw.js?v=7" } },
            { tag: "script", attrs: { type: "module", src: "./search.js?v=7" } },
            { tag: "script", attrs: { type: "module", src: "./config.js?v=7" } },
            { tag: "script", attrs: { type: "module", src: "./index.js?v=7" } },
          ];

          await loadHtmlContent();

          for (const nodeDef of headNodes) {
            await appendHeadNode(nodeDef);
          }
        })();
